    K_RANDN_FILL = hexa_str("extern \"C\" __global__ void randn_fill(float* a, int N, unsigned long long seed, float scale) {\n    int i = blockIdx.x * blockDim.x + threadIdx.x;\n    if (i >= N) return;\n    // splitmix64-style hash on (seed, i) for two uniforms\n    unsigned long long z1 = seed + (unsigned long long)i * 0x9E3779B97F4A7C15ULL + 0xD1B54A32D192ED03ULL;\n    z1 = (z1 ^ (z1 >> 30)) * 0xBF58476D1CE4E5B9ULL;\n    z1 = (z1 ^ (z1 >> 27)) * 0x94D049BB133111EBULL;\n    z1 = z1 ^ (z1 >> 31);\n    unsigned long long z2 = seed + (unsigned long long)i * 0xC2B2AE3D27D4EB4FULL + 0x165667B19E3779F9ULL;\n    z2 = (z2 ^ (z2 >> 30)) * 0xBF58476D1CE4E5B9ULL;\n    z2 = (z2 ^ (z2 >> 27)) * 0x94D049BB133111EBULL;\n    z2 = z2 ^ (z2 >> 31);\n    float u1 = ((float)((z1 >> 11) & 0xFFFFFFULL) + 1.0f) / 16777217.0f;\n    float u2 = ((float)((z2 >> 11) & 0xFFFFFFULL) + 1.0f) / 16777217.0f;\n    float r  = sqrtf(-2.0f * logf(u1));\n    float th = 6.2831853071795864769f * u2;\n    a[i] = r * cosf(th) * scale;\n}\n");
    K_EMBED_LOOKUP_BWD = hexa_str("extern \"C\" __global__ void embed_lookup_bwd(const float* dy, const int* toks, float* dW, int V, int D, int N) {\n    int n = blockIdx.x * blockDim.x + threadIdx.x;\n    int d = blockIdx.y * blockDim.y + threadIdx.y;\n    if (n >= N || d >= D) return;\n    int t = toks[n];\n    atomicAdd(&dW[t * D + d], dy[n * D + d]);\n}\n");
    K_RMS_NORM_BWD = hexa_str("extern \"C\" __global__ void rms_norm_bwd(const float* x, const float* g, const float* dy, const float* rstd, float* dx, float* dg, int N, int D, float eps) {\n    int row = blockIdx.x;\n    int tid = threadIdx.x;\n    if (row >= N || tid >= D) return;\n    extern __shared__ float sdata[];\n    float xv  = x[row * D + tid];\n    float gv  = g[tid];\n    float dyv = dy[row * D + tid];\n    float r   = rstd[row];\n    // coef = sum_d x[d] * g[d] * dy[d]\n    sdata[tid] = xv * gv * dyv;\n    __syncthreads();\n    for (int s = blockDim.x >> 1; s > 0; s >>= 1) {\n        if (tid < s) sdata[tid] += sdata[tid + s];\n        __syncthreads();\n    }\n    float coef = sdata[0];\n    float r3   = r * r * r;\n    dx[row * D + tid] = gv * dyv * r - xv * coef * r3 / (float)D;\n    // dg: atomicAdd across rows — caller passes gpu_zeros(D).\n    atomicAdd(&dg[tid], xv * dyv * r);\n}\n");
    K_SOFTMAX_ROWS_BWD = hexa_str("extern \"C\" __global__ void softmax_rows_bwd(const float* probs, const float* dp, float* ds, int R, int C) {\n    int row = blockIdx.x;\n    int tid = threadIdx.x;\n    if (row >= R || tid >= C) return;\n    extern __shared__ float sdata[];\n    float p = probs[row * C + tid];\n    float d = dp[row * C + tid];\n    sdata[tid] = p * d;\n    __syncthreads();\n    for (int s = blockDim.x >> 1; s > 0; s >>= 1) {\n        if (tid < s) sdata[tid] += sdata[tid + s];\n        __syncthreads();\n    }\n    float sum = sdata[0];\n    ds[row * C + tid] = p * (d - sum);\n}\n");
    K_SWIGLU_BWD = hexa_str("extern \"C\" __global__ void swiglu_bwd(const float* up, const float* gate, const float* dy, float* dup, float* dgate, int N) {\n    int i = blockIdx.x * blockDim.x + threadIdx.x;\n    if (i >= N) return;\n    float g  = gate[i];\n    float s  = 1.0f / (1.0f + expf(-g));\n    float dv = dy[i];\n    dup[i]   = dv * s;\n    dgate[i] = dv * up[i] * s * (1.0f - s);\n}\n");
    K_CE_LOSS_GRAD = hexa_str("extern \"C\" __global__ void ce_loss_grad(const float* logits, const int* targets, float* loss_out, float* dlogits, int R, int C) {\n    int row = blockIdx.x;\n    int tid = threadIdx.x;\n    if (row >= R || tid >= C) return;\n    extern __shared__ float sdata[];\n    float v = logits[row * C + tid];\n    sdata[tid] = v;\n    __syncthreads();\n    // max reduction\n    for (int s = blockDim.x >> 1; s > 0; s >>= 1) {\n        if (tid < s) {\n            float a = sdata[tid];\n            float b = sdata[tid + s];\n            sdata[tid] = a > b ? a : b;\n        }\n        __syncthreads();\n    }\n    float mx = sdata[0];\n    __syncthreads();\n    float e = expf(v - mx);\n    sdata[tid] = e;\n    __syncthreads();\n    for (int s = blockDim.x >> 1; s > 0; s >>= 1) {\n        if (tid < s) sdata[tid] += sdata[tid + s];\n        __syncthreads();\n    }\n    float sum = sdata[0];\n    float lse = mx + logf(sum);\n    int t = targets[row];\n    if (tid == 0) {\n        float row_loss = lse - logits[row * C + t];\n        atomicAdd(loss_out, row_loss / (float)R);\n    }\n    float prob = e / sum;\n    float onehot = (tid == t) ? 1.0f : 0.0f;\n    dlogits[row * C + tid] = (prob - onehot) / (float)R;\n}\n");
