    K_FUSED_ATTN_POST_FWD = hexa_str("extern \"C\" __global__ void fused_attn_post_fwd(const float* scores, float* probs, int R, int C, float inv_sqrt_d) {\n    int row = blockIdx.x;\n    int tid = threadIdx.x;\n    if (row >= R || tid >= C) return;\n    extern __shared__ float sdata[];\n    float v = scores[row * C + tid] * inv_sqrt_d;\n    if (tid > row) v = -1e30f;\n    sdata[tid] = v;\n    __syncthreads();\n    for (int s = blockDim.x >> 1; s > 0; s >>= 1) {\n        if (tid < s) {\n            float a = sdata[tid];\n            float b = sdata[tid + s];\n            sdata[tid] = a > b ? a : b;\n        }\n        __syncthreads();\n    }\n    float mx = sdata[0];\n    __syncthreads();\n    float e = expf(v - mx);\n    sdata[tid] = e;\n    __syncthreads();\n    for (int s = blockDim.x >> 1; s > 0; s >>= 1) {\n        if (tid < s) sdata[tid] += sdata[tid + s];\n        __syncthreads();\n    }\n    float sum = sdata[0];\n    probs[row * C + tid] = e / sum;\n}\n");
